// ── CHART 5: CS5 — Grouped Bar YOY (with growth arrows like PDF)
const growthAnnotationPlugin = {
  id: 'growthAnnotations',
  afterDraw(chart) {
    const ctx = chart.ctx;
    const meta0 = chart.getDatasetMeta(0);
    const meta1 = chart.getDatasetMeta(1);
    const meta2 = chart.getDatasetMeta(2);

    const annotations = [
      { pct: '+148 %', sub: 'Growth', valLabel: '$126,437.00', barTo: meta1.data[0] },
      { pct: '+278 %', sub: 'Growth', valLabel: '$160,719.00', barTo: meta1.data[2] },
      { pct: '+265 %', sub: 'Growth', valLabel: '$128,529.00', barTo: meta2.data[3] },
    ];

    annotations.forEach(a => {
      if (!a.barTo) return;
      const x = a.barTo.x;
      const topY = a.barTo.y;

      ctx.save();

      // Value label just above bar
      ctx.fillStyle = '#333';
      ctx.textAlign = 'center';
      ctx.font = "600 10px 'Manrope', sans-serif";
      ctx.fillText(a.valLabel, x, topY - 8);

      // Arrow line
      ctx.strokeStyle = ORANGE;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(x, topY - 16);
      ctx.lineTo(x, topY - 52);
      ctx.stroke();

      // Arrow head
      ctx.fillStyle = ORANGE;
      ctx.beginPath();
      ctx.moveTo(x - 4, topY - 48);
      ctx.lineTo(x + 4, topY - 48);
      ctx.lineTo(x, topY - 55);
      ctx.closePath();
      ctx.fill();

      // Growth text
      ctx.fillStyle = ORANGE;
      ctx.textAlign = 'center';
      ctx.font = "800 13px 'Manrope', sans-serif";
      ctx.fillText(a.pct, x, topY - 68);
      ctx.font = "700 11px 'Manrope', sans-serif";
      ctx.fillText(a.sub, x, topY - 56);

      ctx.restore();
    });

    // Draw value labels on non-annotated bars
    const allBars = [
      { meta: meta0, data: [85313, 92245, 58117, 43722], color: 'rgba(22,103,232,0.5)' },
      { meta: meta1, data: [126437, 78093, 160719, 48475], color: 'rgba(22,103,232,0.7)', skip: [0, 2] },
      { meta: meta2, data: [null, null, null, 128529], color: BLUE, skip: [3] },
    ];
    allBars.forEach(ds => {
      ds.data.forEach((val, i) => {
        if (val === null) return;
        if (ds.skip && ds.skip.includes(i)) return;
        const bar = ds.meta.data[i];
        if (!bar) return;
        ctx.save();
        ctx.fillStyle = ds.color;
        ctx.textAlign = 'center';
        ctx.font = "600 9px 'Manrope', sans-serif";
        ctx.fillText('$' + val.toLocaleString('en-US', {minimumFractionDigits: 2}), bar.x, bar.y - 6);
        ctx.restore();
      });
    });
  }
};

