      ];
      allBars.forEach(ds => {
        ds.data.forEach((val, i) => {
          if (val === null) return;
          if (ds.skip && ds.skip.includes(i)) return;
          const bar = ds.meta.data[i];
          if (!bar) return;
          ctx.save();
          ctx.fillStyle = ds.color;
          ctx.textAlign = 'center';
          ctx.font = "600 9px 'Manrope', sans-serif";
          ctx.fillText('$' + val.toLocaleString('en-US', {minimumFractionDigits: 2}), bar.x, bar.y - 6);
          ctx.restore();
        });
